final URI home = container.home();
new JdkRequest(UriBuilder.fromUri(home).userInfo("jeff:ffej").toString())
    .through(RetryWire.class)
    .fetch()
    .as(RestResponse.class)
    .assertStatus(HttpURLConnection.HTTP_OK);
